import{V as e,et as t,mt as n,tt as r}from"./chunks/framework.DpI_zlPE.js";var i=JSON.parse(`{"title":"打印机校色文件","description":"","frontmatter":{},"headers":[],"relativePath":"ccc/色彩管理/打印机校色文件分享.md","filePath":"ccc/色彩管理/打印机校色文件分享.md"}`),a={name:`ccc/色彩管理/打印机校色文件分享.md`};function o(e,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[r(`<h1 id="打印机校色文件" tabindex="-1">打印机校色文件 <a class="header-anchor" href="#打印机校色文件" aria-label="Permalink to “打印机校色文件”">​</a></h1><p><a href="https://pan.baidu.com/s/1zSW2UQ2NfF16cG7zuKrDvg?pwd=bxzz" target="_blank" rel="noreferrer">百度网盘</a> 提取码bxzz</p><p>纸厂提供的ICC：<a href="https://www.redrivercatalog.com/profiles/inkjet-printer-color-icc-profiles-red-river-paper.html" target="_blank" rel="noreferrer">红河纸业</a>；<a href="https://www.permajet.com/icc-profiles/" target="_blank" rel="noreferrer">PermaJet</a>；<a href="https://ilford.com/printer-profiles-paper-settings/" target="_blank" rel="noreferrer">ILFORD</a>；<a href="https://www.moabpaper.com/icc-profiles-downloads" target="_blank" rel="noreferrer">Moab</a>；<a href="https://www.farbenwerk.com/en/pages/icc-profile-downloads" target="_blank" rel="noreferrer">farbenwerk</a>；<a href="https://dinax.com/mirage-2/icc-profiles-and-media-packages/?lang=en" target="_blank" rel="noreferrer">Mirage 伪RIP</a>；</p><h2 id="校色文件使用方法" tabindex="-1">校色文件使用方法 <a class="header-anchor" href="#校色文件使用方法" aria-label="Permalink to “校色文件使用方法”">​</a></h2><p><a href="https://www.bilibili.com/video/BV1ZJ4m1L7b9?t=1525.8" target="_blank" rel="noreferrer">校色文件使用方法视频</a></p><h3 id="icc文件" tabindex="-1">ICC文件 <a class="header-anchor" href="#icc文件" aria-label="Permalink to “ICC文件”">​</a></h3><ul><li>将.icm校色文件拷贝到如下目录：</li></ul><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>C:\\Windows\\System32\\spool\\drivers\\color</span></span></code></pre></div><ul><li>打印机设置选择无色彩调整：</li></ul><blockquote><p>墨水，纸张，驱动内介质选择，<strong>特别是质量选项</strong>，对喷墨程序影响很大。使用校色文件要和打印色靶时保持一致。</p></blockquote><p><img src="https://s2.loli.net/2023/08/26/3IDaOXBcR42fyo8.png" alt="l805无色彩管理.png"></p><ul><li>PS将打印机管理颜色改为PS管理颜色，并根据纸张正确加载配置文件：</li></ul><p><img src="https://s2.loli.net/2023/08/26/PEytLx7nOlVZzjK.png" alt="l805无色彩管理PS.png"></p><h3 id="windows颜色管理" tabindex="-1">windows颜色管理 <a class="header-anchor" href="#windows颜色管理" aria-label="Permalink to “windows颜色管理”">​</a></h3><blockquote><p>如果不方便用adobe软件可以用windows自带的颜色管理。</p><p>截止win11 24H2，windows右键打印只能打sRGB的图片，不会加载图片的ICC。</p></blockquote><p>右键图片，打印，拉起windows打印。选项，颜色管理，设备修改为打印机，启用使用我对此设备的设置，配置文件选择改为手动。</p><p>按右下角的配置文件按钮，加载标准关联，打开校色配置文件。选中加载进去的校色文件，设置为默认值。</p><p>如果加载后提示不匹配，把打印机校色文件拷到</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>C:\\Windows\\System32\\spool\\drivers\\color</span></span></code></pre></div><p>在颜色管理界面按左下角的添加。之后选中加载进去的校色文件，设置为默认值。</p><p>爱普生：打印机属性，更多选项，色彩调整-高级，设置为<strong>无色彩调整</strong>，不要设置成ICM，然后打印。</p><p><strong>选ICM还是无色彩管理，根据软件不同自行测试对比。</strong>windows右键打印调用SetICMMode，驱动应设为无色彩管理。如果软件调用DMICMMETHOD，则驱动可能需要设置为ICM，好像WPS或浏览器直接打印是这种方式。颜色管理内设置需要用的ICC为默认是一样的。</p><h3 id="lut补偿" tabindex="-1">Lut补偿 <a class="header-anchor" href="#lut补偿" aria-label="Permalink to “Lut补偿”">​</a></h3><p>我感觉效果不错，但由于做法是我自己弄出来的，不确定是否正确。</p><p><a href="https://www.bilibili.com/video/BV1K6WTzkENi" target="_blank" rel="noreferrer">色差仪生成补偿LUT</a>；<a href="https://www.bilibili.com/video/BV1dD421L7YB" target="_blank" rel="noreferrer">扫描仪生成补偿LUT</a>；色差仪视频是后录的，应该说整体相对更合理，原理都是一样的，用扫描仪生成最好也参考色差仪，只不过色差仪扫描色值并生成图片那一步改成图片用扫描仪扫描。</p><p>1、PS软件打开要打印的图片。</p><p>2、新建调整-颜色查找涂层。</p><p><img src="https://s2.loli.net/2023/08/29/xUgSd39s4cFVwWD.png" alt="补偿lut-1.png"></p><p>3、点击载入3D lut后再点击载入3D lut，之后选中.cube文件。</p><blockquote><p>注意lut文件是有对应色彩空间的，打印前运用PS的转换为配置文件，相对比色意图转换到对应色彩空间加载后打印。<a href="https://link.zhihu.com/?target=http%3A//hivii.ysepan.com/" target="_blank" rel="noreferrer">标准色彩配置文件转载，附件-色彩管理-标准ICC</a>。</p><p>一般是ProPhoto或P3。</p></blockquote><p><img src="https://s2.loli.net/2023/08/29/9ZSaPmRAq62IDL4.png" alt="补偿lut-2.png"></p><p>之后再打印，打印稿可能相对更接近屏幕显示效果。</p>`,32)]])}var s=e(a,[[`render`,o]]);export{i as __pageData,s as default};